mapper.sql:
where d.company_id = #{companyId,jdbcType=VARCHAR}
  and d.content_kind = #{contentKind,jdbcType=VARCHAR}


  and d.document_category_id = #{documentCategoryId,jdbcType=VARCHAR}


  and trim(coalesce(d.created_by, '')) = #{createdBy,jdbcType=VARCHAR}

where d.company_id = #{companyId,jdbcType=VARCHAR}
  and d.content_kind = #{contentKind,jdbcType=VARCHAR}


  and d.title ilike concat('%', #{titleQuery,jdbcType=VARCHAR}, '%')

( not exists ( select 1 from document_access_rules r0 where r0.company_id = d.company_id and r0.document_id = d.document_id and upper(trim(coalesce(r0.status, ''))) = 'ACTIVE' ) or exists ( select 1 from document_access_rules r where r.company_id = d.company_id and r.document_id = d.document_id and upper(trim(coalesce(r.status, ''))) = 'ACTIVE' and ( (r.role_id is null or length(trim(r.role_id)) = 0)
or r.role_id in
#{rid,jdbcType=VARCHAR}
) and ( (r.department_id is null or length(trim(r.department_id)) = 0) or (#{departmentId,jdbcType=VARCHAR} is not null and r.department_id = #{departmentId,jdbcType=VARCHAR}) ) ) )

mapper.select:
select count(1)
from documents d
where d.company_id = #{companyId,jdbcType=VARCHAR}
  and d.content_kind = #{contentKind,jdbcType=VARCHAR}


  and d.title ilike concat('%', #{titleQuery,jdbcType=VARCHAR}, '%')

and

select d.document_id, d.company_id, d.document_category_id, d.title, d.description, d.visibility,
       d.status, d.created_by, d.created_at, d.updated_at, d.content_kind, d.draft_json, d.published_json,
       d.published_at, d.published_by
from documents d
where d.company_id = #{companyId,jdbcType=VARCHAR}
  and d.content_kind = #{contentKind,jdbcType=VARCHAR}


  and d.title ilike concat('%', #{titleQuery,jdbcType=VARCHAR}, '%')

and 
order by d.updated_at desc nulls last, d.created_at desc
limit #{limit} offset #{offset}
